import React from "react";
import LazyImage from "./LazyImage";
import { getImage } from "../../utils/getImage";

export default function Grid({
  items,
  selectedId,
  onSelect,
  hoveredId,
  setHovered,
  isSingle,
}) {
  return (
    <div
      style={{
        display: "grid",
        gridTemplateColumns: isSingle
          ? "repeat(auto-fit, minmax(260px, 1fr))"
          : "repeat(auto-fill, minmax(190px, 1fr))",
        gap: "14px",
        gridAutoRows: "1fr",
        alignItems: "stretch",
      }}
    >
      {items.map((item) => {
        const isSelected = selectedId === item.id;

        return (
          <button
            key={item.id}
            onClick={() => onSelect(item)}
            onMouseEnter={() => setHovered(item.id)}
            onMouseLeave={() => setHovered(null)}
            style={{
              all: "unset",
              cursor: "pointer",
              display: "flex",
              flexDirection: "column",
              height: "100%",
            }}
          >
            {/* TARJETA */}
            <div
              style={{
                borderRadius: "12px",
                overflow: "hidden",
                background: "#fff",
                boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
                transition: "transform 0.2s ease",
                transform: hoveredId === item.id ? "scale(1.02)" : "scale(1)",
                boxShadow: hoveredId === item.id
                  ? "0 8px 20px rgba(0,0,0,0.15)"
                  : "0 4px 12px rgba(0,0,0,0.08)",
                display: "flex",
                flexDirection: "column",
                height: "100%",
                width: "100%",
              }}
            >
              {/* IMAGEN */}
              <div
                style={{
                  width: "100%",
                  aspectRatio: "3 / 4",
                  overflow: "hidden",
                  background: "#eee",
                  flexShrink: 0,
                }}
              >
                <LazyImage
  src={getImage(item, "thumb")}
  alt={item.titulo}
/>
              </div>

              {/* TEXTO */}
              <div
                style={{
                  padding: "8px 10px",
                  flex: 1,
                  display: "flex",
                  flexDirection: "column",
                  justifyContent: "flex-start",
                }}
              >
                <div
                  style={{
                    fontSize: "13px",
                    fontWeight: "600",
                    color: "#333",
                    lineHeight: 1.2,
                    fontFamily: "'Montserrat', sans-serif",
                  }}
                >
                  {item.titulo}
                </div>

                {item.descripcion && (
                  <div
                    style={{
                      fontSize: "11px",
                      color: "#777",
                      marginTop: "2px",
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                      display: "-webkit-box",
                      WebkitLineClamp: 2,
                      WebkitBoxOrient: "vertical",
                      fontFamily: "'Montserrat', sans-serif",
                    }}
                  >
                    {item.descripcion}
                  </div>
                )}
              </div>
            </div>
          </button>
        );
      })}
    </div>
  );
}
